import { useState, useMemo, useEffect, useCallback } from "react";
import { supabase } from "./supabase";
import * as XLSX from "xlsx";

// Quality: MO/CO groups (based on percentage values, stored as decimals)
const moP=l=>((l.mo||0)*100);const coP=l=>((l.co||0)*100);
const grp=v=>v<=2?0:v<=4?1:v<=6?2:3;
const GRP=[{l:"0-2%",c:"#1e8449",bg:"#e8f8ef"},{l:"2-4%",c:"#d68910",bg:"#fdf2e0"},{l:"4-6%",c:"#c0392b",bg:"#fbeaea"},{l:">6%",c:"#922b21",bg:"#f5d5d1"}];
const pct=v=>((v||0)*100).toFixed(2)+"%";
const pctN=v=>((v||0)*100).toFixed(2);
const dsp=l=>(l.q_iniz||0)-(l.mov||0);
const fmtD=d=>{if(!d)return"-";const p=String(d).split("T")[0].split("-");return p.length===3?p[2]+"/"+p[1]+"/"+p[0]:d};
const xls=(data,cols,name)=>{const rows=data.map(r=>{const o={};cols.forEach(c=>{o[c.label]=c.gv?c.gv(r):r[c.key]??""});return o});const ws=XLSX.utils.json_to_sheet(rows);const wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,ws,"Dati");XLSX.writeFile(wb,name+".xlsx")};
const LAV_ORD={"SGUSCIATE":0,"SCARTI":1,"ROTTAME":2};
const CAL_ORD={"9/11":0,"11/13":1,"13/15":2,"DA SCEGLIERE":3,"VENTILATO":4,"PICCOLO":5,"GRANDE":6,"GRANELLA":7,"FARINA":8,"PASTA":9};
const stdSort=(a,b)=>{if(a.desc1!==b.desc1)return a.desc1.localeCompare(b.desc1);const la=LAV_ORD[a.desc2]??9,lb=LAV_ORD[b.desc2]??9;if(la!==lb)return la-lb;const ca=CAL_ORD[a.desc3]??99,cb=CAL_ORD[b.desc3]??99;if(ca!==cb)return ca-cb;if(a.lotto!==b.lotto)return a.lotto.localeCompare(b.lotto);return a.imballo.localeCompare(b.imballo)};
// Subtotal calculator
const calcSub=(items)=>{const t=items.reduce((s,l)=>s+l.d,0);const n=items.length;const avg=(field)=>n>0?(items.reduce((s,l)=>s+((l[field]||0)*100),0)/n).toFixed(2):"0";return{t,n,mv:avg("mv"),mo:avg("mo"),cv:avg("cv"),co:avg("co"),ce:avg("ce"),rt:avg("rt")}};

const LIGHT={bg:"#f5f3ef",sf:"#ffffff",sfH:"#f0ece4",card:"#ffffff",bd:"#e2ddd4",bdH:"#c9a84c88",acc:"#b8892e",accD:"#8a6820",accL:"#f5e6c8",g:"#2d8a4e",gD:"#e6f5ec",r:"#c0392b",rD:"#fbeaea",o:"#d68910",oD:"#fdf2e0",b:"#2471a3",bD:"#e4f0f9",t:"#2c2418",tD:"#6b5e4f",tM:"#9a8d7e",pk:"#faf6ef",pkS:"#f5eed8",zebra:"#faf8f4",thBg:"#f8f5f0"};
const DARK={bg:"#080c10",sf:"#12171e",sfH:"#1a2029",card:"#151b24",bd:"#252d38",bdH:"#c9a84c88",acc:"#d4a855",accD:"#a3833e",accL:"#d4a85520",g:"#4ade80",gD:"#4ade8018",r:"#f87171",rD:"#f8717118",o:"#fb923c",oD:"#fb923c18",b:"#60a5fa",bD:"#60a5fa18",t:"#e8e0d4",tD:"#8899aa",tM:"#5a6a7a",pk:"#1a2029",pkS:"#1e2836",zebra:"#111820",thBg:"#0d1218"};
var C=LIGHT;
const TC={"CONVENZIONALI":"#b8892e","BIOLOGICHE":"#1e8449","GIFFONI":"#2471a3","FAIR FOR LIFE":"#7d3c98","BIOSUISSE":"#c0392b"};
const TIPI=["CONVENZIONALI","BIOLOGICHE","FAIR FOR LIFE","BIOSUISSE","GIFFONI"];
const LAVS=["SGUSCIATE","ROTTAME","SCARTI"];
const CALS=["9/11","11/13","13/15","DA SCEGLIERE","VENTILATO","PICCOLO","GRANDE","GRANELLA","FARINA","PASTA"];
const MAGS=["Caprarola","Soriano","Fabbrica","Vignanello"];
const XC={
  giacenze:[{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Calibro"},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Disp.",gv:r=>dsp(r)},{key:"magazzino",label:"Mag."},{label:"M.V.%",gv:r=>pctN(r.mv)},{label:"M.O.%",gv:r=>pctN(r.mo)},{label:"C.V.%",gv:r=>pctN(r.cv)},{label:"C.O.%",gv:r=>pctN(r.co)},{label:"C.E.%",gv:r=>pctN(r.ce)},{label:"RT%",gv:r=>pctN(r.rt)},{key:"contratto",label:"Contr."},{key:"acquirente",label:"Acq."}],
  lotti:[{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{key:"q_iniz",label:"Q.Iniz"},{key:"mov",label:"Mov."},{label:"Disp.",gv:r=>dsp(r)},{key:"magazzino",label:"Mag."},{key:"contratto",label:"Contr."}],
  contratti:[{key:"id",label:"N."},{key:"cliente",label:"Cliente"},{key:"desc1",label:"Tipo"},{key:"desc3",label:"Cal."},{key:"qta_tot",label:"Totale"},{key:"qta_evasa",label:"Evasa"},{label:"Residuo",gv:r=>(r.qta_tot||0)-(r.qta_evasa||0)},{label:"Scadenza",gv:r=>fmtD(r.scadenza)}],
  movimenti:[{key:"tipo",label:"Tipo Mov."},{label:"Data",gv:r=>fmtD(r.data)},{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{key:"qta",label:"Qta"},{key:"magazzino",label:"Mag."},{key:"contratto_id",label:"Contr."},{key:"cliente",label:"Cliente"},{key:"acquirente",label:"Acq."}],
};
const CSS=`@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800;900&family=DM+Mono:wght@400;500&family=Playfair+Display:wght@700;800;900&display=swap');
::selection{background:#b8892e44}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:#ccc;border-radius:3px}
@keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
@keyframes slideIn{from{opacity:0;transform:translateX(-8px)}to{opacity:1;transform:translateX(0)}}
@keyframes barGrow{from{width:0}}
@media print{*{color:black!important;background:white!important;box-shadow:none!important;border-color:#ccc!important}[data-no-print]{display:none!important}table{width:100%!important;border-collapse:collapse!important;page-break-inside:auto!important;font-size:9px!important}tr{page-break-inside:avoid!important}th{background:#eee!important;border:1px solid #999!important;padding:4px 6px!important;font-size:8px!important;font-weight:700!important;text-transform:uppercase!important}td{border:1px solid #bbb!important;padding:3px 6px!important;font-size:9px!important;white-space:normal!important;word-break:break-word!important}span{background:none!important;border:none!important;padding:0!important}h1{font-size:16px!important}div[style*="overflow"]{overflow:visible!important;max-height:none!important}@page{margin:0.8cm;size:A4 landscape}}
@media(max-width:1200px){td,th{padding:6px 8px!important;font-size:12px!important}}
@media(max-width:900px){td,th{padding:4px 6px!important;font-size:11px!important}}`;

const Badge=({children,color,bg,onClick,style:s})=><span onClick={onClick} style={{display:"inline-block",padding:"3px 10px",borderRadius:5,fontSize:11,fontWeight:700,letterSpacing:.3,color:color||C.t,background:bg||C.zebra,cursor:onClick?"pointer":"default",transition:"all .15s",...s}}>{children}</span>;
const Msg=({msg})=>msg?<div style={{padding:"10px 16px",borderRadius:8,marginBottom:16,background:msg.t==="ok"?C.gD:C.rD,color:msg.t==="ok"?C.g:C.r,border:"1px solid "+(msg.t==="ok"?C.g+"33":C.r+"33"),fontSize:13,animation:"fadeUp .3s both"}}>{msg.x}</div>:null;
const Tbl=({cols,data,onRow})=><div style={{borderRadius:10,border:"1px solid "+C.bd,overflow:"auto",background:C.sf,maxWidth:"100%"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13,minWidth:600}}><thead><tr>{cols.map((c,i)=><th key={i} style={{padding:"10px 12px",textAlign:"left",background:C.thBg,color:C.tD,fontSize:10,textTransform:"uppercase",letterSpacing:.8,borderBottom:"2px solid "+C.acc,whiteSpace:"nowrap",fontWeight:700,position:"sticky",top:0,zIndex:1}}>{c.label}</th>)}</tr></thead><tbody>{data.length===0?<tr><td colSpan={cols.length} style={{padding:30,textAlign:"center",color:C.tM}}>Nessun dato</td></tr>:data.map((row,ri)=>row._blank?<tr key={"bl"+ri}><td colSpan={cols.length} style={{padding:4,background:C.bg}}></td></tr>:row._sub?<tr key={"sub"+ri} style={{background:row._level==="tipo"?C.accL:row._level==="lav"?C.gD:C.zebra,borderTop:row._level==="tipo"?"2px solid "+C.acc:row._level==="lav"?"2px solid "+C.g:"1px solid "+C.bd}}>{cols.map((c,ci)=><td key={ci} style={{padding:"7px 12px",fontWeight:row._level==="tipo"?800:700,fontSize:row._level==="tipo"?12:11,color:row._level==="tipo"?C.acc:row._level==="lav"?C.g:C.tD,whiteSpace:"nowrap",fontStyle:row._level==="cal"?"italic":"normal"}}>{c.subRender?c.subRender(row):""}</td>)}</tr>:<tr key={row.id||ri} onClick={()=>onRow&&onRow(row)} style={{cursor:onRow?"pointer":"default",background:ri%2===0?C.sf:C.zebra,transition:"background .15s"}} onMouseEnter={e=>{e.currentTarget.style.background=C.sfH}} onMouseLeave={e=>{e.currentTarget.style.background=ri%2===0?C.sf:C.zebra}}>{cols.map((c,ci)=><td key={ci} style={{padding:"9px 12px",borderBottom:"1px solid "+C.bd+"66",whiteSpace:"nowrap",color:C.t}}>{c.render?c.render(row):row[c.key]}</td>)}</tr>)}</tbody></table></div>;
const Sel=({label,value,onChange,options,style:s})=><div style={{display:"flex",flexDirection:"column",gap:4,...s}}>{label&&<label style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:.8,fontWeight:600}}>{label}</label>}<select value={value} onChange={e=>onChange(e.target.value)} style={{padding:"8px 12px",background:C.sf,border:"1px solid "+C.bd,borderRadius:8,color:C.t,fontSize:13,outline:"none"}}>{options.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</select></div>;
const Inp=({label,value,onChange,type,placeholder,style:s,disabled})=><div style={{display:"flex",flexDirection:"column",gap:4,...s}}>{label&&<label style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:.8,fontWeight:600}}>{label}</label>}<input type={type||"text"} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} disabled={disabled} style={{padding:"8px 12px",background:disabled?C.bd+"44":C.sf,border:"1px solid "+C.bd,borderRadius:8,color:disabled?C.tM:C.t,fontSize:13,outline:"none",opacity:disabled?.6:1}}/></div>;
const Btn=({children,onClick,primary,small,disabled,danger,style:s})=><button onClick={onClick} disabled={disabled} style={{padding:small?"6px 14px":"10px 20px",borderRadius:8,border:"1px solid "+(danger?C.r:primary?C.acc:C.bd),cursor:disabled?"not-allowed":"pointer",fontWeight:700,fontSize:small?12:13,background:danger?C.r:primary?C.acc:C.sf,color:danger||primary?"#fff":C.t,opacity:disabled?.5:1,transition:"all .15s",boxShadow:primary?"0 2px 8px "+C.acc+"33":"none",...s}}>{children}</button>;
const XBtn=({data,cols,name})=>data&&data.length>0?<div data-no-print style={{display:"flex",gap:6}}><Btn small onClick={()=>xls(data,cols,name||"export")}>Excel</Btn><Btn small onClick={()=>window.print()}>Stampa</Btn></div>:null;
const GCard=({children,onClick,delay,style:s})=><div onClick={onClick} style={{background:C.card,border:"1px solid "+C.bd,borderRadius:14,padding:22,cursor:onClick?"pointer":"default",transition:"all .2s",animation:`fadeUp .4s ${delay||0}s both`,boxShadow:"0 1px 3px rgba(0,0,0,0.04)",...s}} onMouseEnter={e=>{if(onClick){e.currentTarget.style.transform="translateY(-3px)";e.currentTarget.style.boxShadow="0 8px 24px rgba(0,0,0,0.08)"}}} onMouseLeave={e=>{e.currentTarget.style.transform="";e.currentTarget.style.boxShadow="0 1px 3px rgba(0,0,0,0.04)"}}>{children}</div>;
const TypeChip=({label,active,color,onClick})=><button onClick={onClick} style={{padding:"8px 18px",borderRadius:20,border:"2px solid "+(active?color:C.bd),background:active?color+"15":C.sf,color:active?color:C.tD,fontSize:12,fontWeight:active?700:500,cursor:"pointer",transition:"all .2s"}}>{label}</button>;

// === LOGIN ===
function LoginPage(){const[em,setEm]=useState("");const[pw,setPw]=useState("");const[ld,setLd]=useState(false);const[er,setEr]=useState("");const go=async()=>{setLd(true);setEr("");const{error}=await supabase.auth.signInWithPassword({email:em,password:pw});if(error)setEr("Email o password errati");setLd(false)};return <div style={{height:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.bg}}><style>{CSS}</style><div style={{width:400,background:C.card,border:"1px solid "+C.bd,borderRadius:18,padding:48,boxShadow:"0 4px 24px rgba(0,0,0,0.06)",animation:"fadeUp .5s both"}}><div style={{textAlign:"center",marginBottom:36}}><div style={{width:56,height:56,borderRadius:14,background:"linear-gradient(135deg,"+C.acc+","+C.accD+")",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:22,fontWeight:900,color:"#fff",marginBottom:16}}>A</div><h1 style={{fontSize:26,fontWeight:900,color:C.acc,margin:"8px 0 4px",fontFamily:"'Playfair Display',serif"}}>ASSOFRUTTI</h1><p style={{fontSize:13,color:C.tM,margin:0,letterSpacing:2}}>MAGAZZINO NOCCIOLE</p></div>{er&&<div style={{padding:"10px 14px",borderRadius:8,background:C.rD,color:C.r,fontSize:12,marginBottom:16}}>{er}</div>}<Inp label="Email" value={em} onChange={setEm} placeholder="mario@assofrutti.it" type="email"/><div style={{height:14}}/><Inp label="Password" value={pw} onChange={setPw} placeholder="........" type="password"/><div style={{height:24}}/><Btn primary onClick={go} disabled={ld||!em||!pw} style={{width:"100%",padding:"14px",fontSize:15}}>{ld?"Accesso...":"Accedi"}</Btn></div></div>;}

// === DASHBOARD (detailed per tipo/calibro/lavorazione) ===
function DashboardPage({lotti,contratti,goPage}){
  const av=useMemo(()=>lotti.filter(l=>dsp(l)>0).map(l=>({...l,d:dsp(l)})),[lotti]);
  const tot=av.reduce((s,l)=>s+l.d,0);
  const openC=contratti.filter(c=>(c.qta_tot-c.qta_evasa)>0);
  const drill=(type,val)=>goPage("giacenze",{type,val});

  // Per-tipo detail builder
  const tipoDetail=(tipo)=>{
    const items=av.filter(l=>l.desc1===tipo);if(items.length===0)return null;
    const tTot=items.reduce((s,l)=>s+l.d,0);
    const sg=items.filter(l=>l.desc2==="SGUSCIATE");const rt=items.filter(l=>l.desc2==="ROTTAME");const sc=items.filter(l=>l.desc2==="SCARTI");
    const sgTot=sg.reduce((s,l)=>s+l.d,0);const rtTot=rt.reduce((s,l)=>s+l.d,0);const scTot=sc.reduce((s,l)=>s+l.d,0);
    // Calibri sgusciato
    const sgCal={};sg.forEach(l=>{if(!sgCal[l.desc3])sgCal[l.desc3]={kg:0,n:0,mo:0,co:0};sgCal[l.desc3].kg+=l.d;sgCal[l.desc3].n++;sgCal[l.desc3].mo+=(l.mo||0)*100;sgCal[l.desc3].co+=(l.co||0)*100});
    const calEntries=Object.entries(sgCal).sort((a,b)=>(CAL_ORD[a[0]]??99)-(CAL_ORD[b[0]]??99));
    // MO/CO group counts (sgusciato only)
    const moGrp=[0,0,0,0];sg.forEach(l=>{moGrp[grp(moP(l))]++});
    const coGrp=[0,0,0,0];sg.forEach(l=>{coGrp[grp(coP(l))]++});
    const color=TC[tipo]||C.acc;
    return <GCard key={tipo} delay={.1} style={{marginBottom:16}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,cursor:"pointer"}} onClick={()=>drill("tipo",tipo)}>
        <div style={{display:"flex",alignItems:"center",gap:10}}><span style={{width:14,height:14,borderRadius:4,background:color,display:"inline-block"}}/><h2 style={{fontSize:18,fontWeight:800,margin:0,color:C.t}}>{tipo}</h2></div>
        <div style={{fontSize:24,fontWeight:900,color,fontFamily:"'DM Mono',monospace"}}>{tTot.toLocaleString()} <span style={{fontSize:13,color:C.tM}}>kg</span></div>
      </div>
      {/* SGUSCIATO detail */}
      {sgTot>0&&<div style={{marginBottom:14}}><div style={{fontSize:13,color:C.tD,fontWeight:700,textTransform:"uppercase",letterSpacing:1,marginBottom:8}}>Sgusciate — {sgTot.toLocaleString()} kg ({sg.length} lotti)</div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12}}>{calEntries.map(([cal,d])=>{const avgMo=(d.mo/d.n).toFixed(2);const avgCo=(d.co/d.n).toFixed(2);return <div key={cal} onClick={()=>goPage("giacenze",{type:"sg_cal_tipo",val:cal+"|"+tipo})} style={{cursor:"pointer",background:C.zebra,borderRadius:10,padding:"10px 14px",border:"1px solid "+C.bd,flex:"1 1 100px",minWidth:90,transition:"all .15s"}} onMouseEnter={e=>{e.currentTarget.style.borderColor=C.bdH}} onMouseLeave={e=>{e.currentTarget.style.borderColor=C.bd}}>
        <div style={{fontSize:17,fontWeight:800,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{cal}</div>
        <div style={{fontSize:20,fontWeight:700,fontFamily:"'DM Mono',monospace",marginTop:4}}>{d.kg.toLocaleString()} <span style={{fontSize:12,color:C.tM}}>kg</span></div>
        <div style={{fontSize:11,color:C.tM,marginTop:4}}>{d.n} lotti</div>
        <div style={{display:"flex",gap:8,marginTop:6,fontSize:12}}><span>MO <b style={{color:Number(avgMo)>4?C.r:Number(avgMo)>2?C.o:C.g}}>{avgMo}%</b></span><span>CO <b style={{color:Number(avgCo)>4?C.r:Number(avgCo)>2?C.o:C.g}}>{avgCo}%</b></span></div>
      </div>})}</div>
      {/* MO/CO groups */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <div><div style={{fontSize:11,color:C.tD,fontWeight:600,marginBottom:6}}>MARCIO OCCULTO</div><div style={{display:"flex",gap:4}}>{moGrp.map((n,i)=><div key={i} onClick={()=>n>0&&goPage("giacenze",{type:"moGrp_tipo",val:i+"|"+tipo})} style={{flex:1,textAlign:"center",padding:"6px 0",background:GRP[i].bg,borderRadius:6,border:"1px solid "+GRP[i].c+"33",cursor:n>0?"pointer":"default"}}><div style={{fontSize:16,fontWeight:800,color:GRP[i].c}}>{n}</div><div style={{fontSize:9,color:C.tD}}>{GRP[i].l}</div></div>)}</div></div>
        <div><div style={{fontSize:11,color:C.tD,fontWeight:600,marginBottom:6}}>CIMICIATO OCCULTO</div><div style={{display:"flex",gap:4}}>{coGrp.map((n,i)=><div key={i} onClick={()=>n>0&&goPage("giacenze",{type:"coGrp_tipo",val:i+"|"+tipo})} style={{flex:1,textAlign:"center",padding:"6px 0",background:GRP[i].bg,borderRadius:6,border:"1px solid "+GRP[i].c+"33",cursor:n>0?"pointer":"default"}}><div style={{fontSize:16,fontWeight:800,color:GRP[i].c}}>{n}</div><div style={{fontSize:9,color:C.tD}}>{GRP[i].l}</div></div>)}</div></div>
      </div></div>}
      {/* Rottame/Scarti compact */}
      <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
        {rtTot>0&&<div style={{background:C.oD,borderRadius:8,padding:"8px 14px",flex:"1 1 100px",cursor:"pointer"}} onClick={()=>goPage("giacenze",{type:"lav_tipo",val:"ROTTAME|"+tipo})}><span style={{fontSize:10,color:C.o,fontWeight:700}}>ROTTAME</span><div style={{fontSize:18,fontWeight:800,color:C.o,fontFamily:"'DM Mono',monospace"}}>{rtTot.toLocaleString()} kg</div><div style={{fontSize:11,color:C.tM}}>{rt.length} lotti</div></div>}
        {scTot>0&&<div style={{background:C.rD,borderRadius:8,padding:"8px 14px",flex:"1 1 100px",cursor:"pointer"}} onClick={()=>goPage("giacenze",{type:"lav_tipo",val:"SCARTI|"+tipo})}><span style={{fontSize:10,color:C.r,fontWeight:700}}>SCARTI</span><div style={{fontSize:18,fontWeight:800,color:C.r,fontFamily:"'DM Mono',monospace"}}>{scTot.toLocaleString()} kg</div><div style={{fontSize:11,color:C.tM}}>{sc.length} lotti</div></div>}
      </div>
    </GCard>;
  };

  return <div>
    <div style={{marginBottom:28}}><h1 style={{fontSize:32,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif",animation:"fadeUp .4s both"}}>Dashboard</h1><p style={{color:C.tM,fontSize:14,marginTop:6}}>Clicca su qualsiasi dato per esplorare nel dettaglio</p></div>
    {/* KPI row */}
    <div style={{display:"flex",gap:14,marginBottom:28,flexWrap:"wrap"}}>
      <GCard delay={.05} onClick={()=>goPage("giacenze")} style={{flex:"1 1 200px"}}><div style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:1.5,marginBottom:8,fontWeight:600}}>Giacenza Totale</div><div style={{fontSize:30,fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{tot.toLocaleString()} <span style={{fontSize:14,color:C.tM}}>kg</span></div><div style={{fontSize:12,color:C.tM,marginTop:4}}>{av.length} lotti</div></GCard>
      <GCard delay={.1} onClick={()=>goPage("contratti")} style={{flex:"1 1 200px"}}><div style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:1.5,marginBottom:8,fontWeight:600}}>Contratti Aperti</div><div style={{fontSize:30,fontWeight:900,color:C.o,fontFamily:"'DM Mono',monospace"}}>{openC.length}</div><div style={{fontSize:12,color:C.tM,marginTop:4}}>su {contratti.length}</div></GCard>
      {/* Per-magazzino compact */}
      {Object.entries((() => { const m = {}; av.forEach(l => { m[l.magazzino] = (m[l.magazzino] || 0) + l.d }); return m })()).sort((a,b)=>b[1]-a[1]).map(([mag,kg])=><GCard key={mag} delay={.15} onClick={()=>drill("magazzino",mag)} style={{flex:"1 1 140px"}}><div style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:1,marginBottom:6,fontWeight:600}}>{mag}</div><div style={{fontSize:22,fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{kg.toLocaleString()}</div><div style={{fontSize:11,color:C.tM}}>{tot>0?(kg/tot*100).toFixed(0):0}%</div></GCard>)}
    </div>
    {/* Per-tipo detailed sections */}
    <h2 style={{fontSize:14,color:C.tD,textTransform:"uppercase",letterSpacing:2,marginBottom:14,fontWeight:600}}>Dettaglio per Tipologia</h2>
    {TIPI.map(t=>tipoDetail(t))}
    {/* Contratti aperti */}
    <GCard delay={.5} style={{marginTop:14}}><h2 style={{fontSize:13,color:C.tD,textTransform:"uppercase",letterSpacing:2,marginBottom:14,fontWeight:600}}>Contratti Aperti</h2><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:10}}>{openC.map((c,i)=>{const res=c.qta_tot-c.qta_evasa;const p=c.qta_evasa/c.qta_tot*100;return <div key={c.id} onClick={()=>goPage("contratti",{type:"contr",val:c.id})} style={{background:C.zebra,borderRadius:10,padding:14,border:"1px solid "+C.bd,cursor:"pointer",transition:"all .15s"}} onMouseEnter={e=>{e.currentTarget.style.borderColor=C.bdH}} onMouseLeave={e=>{e.currentTarget.style.borderColor=C.bd}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}><span style={{fontWeight:700,color:C.acc,fontSize:13}}>N.{c.id} — {c.cliente}</span><span style={{fontSize:11,color:C.tM}}>{fmtD(c.scadenza)}</span></div><div style={{display:"flex",justifyContent:"space-between",marginBottom:6,fontSize:12}}><span style={{color:C.tM}}>Residuo: <strong style={{color:C.o}}>{res.toLocaleString()} kg</strong></span><span style={{color:C.tM,fontFamily:"'DM Mono',monospace"}}>{p.toFixed(0)}%</span></div><div style={{height:4,background:C.bd+"44",borderRadius:2,overflow:"hidden"}}><div style={{height:"100%",width:p+"%",background:p>=100?C.g:C.acc,borderRadius:2}}/></div></div>})}</div></GCard>
  </div>;
}

// === MOVIMENTI ===
function MovimentiPage({lotti,contratti,reload}){
  const[tipo,setTipo]=useState("ENTRATA");const[msg,setMsg]=useState(null);const[loading,setLoading]=useState(false);const[selIds,setSelIds]=useState([]);
  const ef={data:new Date().toISOString().split("T")[0],sett:"",anno:"2025",imballo:"",lotto:"",desc1:"CONVENZIONALI",desc2:"SGUSCIATE",desc3:"9/11",qta:"",magazzino:"Fabbrica",mv:"",mo:"",cv:"",co:"",ce:"",rt:"",newMag:"Soriano"};
  const[form,setForm]=useState(ef);const[sel,setSel]=useState(null);const reset=()=>{setForm(ef);setSel(null);setSelIds([])};const chTipo=v=>{setTipo(v);reset()};
  const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),5000)};
  const fc=lot=>contratti.find(c=>c.id===lot.contratto&&(c.qta_tot-c.qta_evasa)>0);
  const checkDup=()=>lotti.some(l=>l.lotto===form.lotto&&l.imballo===form.imballo&&l.desc1===form.desc1&&l.desc3===form.desc3);
  const[fTipo,setFTipo]=useState("");const[fCal,setFCal]=useState("");const[fMag,setFMag]=useState("");const[fSt,setFSt]=useState("");
  const av=useMemo(()=>lotti.filter(l=>dsp(l)>0).map(l=>({...l,d:dsp(l),stato:(l.contratto||l.acquirente)?"A":"L"})).sort(stdSort),[lotti]);
  const ufl=av.filter(l=>{if(fTipo&&l.desc1!==fTipo)return false;if(fCal&&l.desc3!==fCal)return false;if(fMag&&l.magazzino!==fMag)return false;if(fSt&&l.stato!==fSt)return false;return true});
  const toggleSel=id=>setSelIds(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);

  const handleSubmit=async()=>{if(loading)return;if(!form.qta||Number(form.qta)<=0){flash("err","Quantita non valida");return}
    if(tipo==="ENTRATA"){if(!form.imballo||!form.lotto){flash("err","Compila imballo e lotto");return}if(checkDup()){flash("err","Esiste gia un lotto con stessi Lotto, Imballo, Tipo e Calibro!");return}}
    if(tipo==="TRASFERIMENTO"&&!sel){flash("err","Seleziona un lotto");return}
    if(tipo==="TRASFERIMENTO"&&sel&&Number(form.qta)>sel.d){flash("err","Max: "+sel.d+" kg");return}
    if(tipo==="USCITA"&&!sel){flash("err","Seleziona un lotto");return}
    if(tipo==="USCITA"&&sel&&Number(form.qta)>sel.d){flash("err","Max: "+sel.d+" kg");return}
    const q=Number(form.qta);setLoading(true);try{
      if(tipo==="ENTRATA"){const{error:e1}=await supabase.from("lotti").insert({sett_prod:Number(form.sett)||0,anno:Number(form.anno),imballo:form.imballo,lotto:form.lotto,desc1:form.desc1,desc2:form.desc2,desc3:form.desc3,q_iniz:q,mov:0,magazzino:form.magazzino,mv:(Number(form.mv)||0)/100,mo:(Number(form.mo)||0)/100,cv:(Number(form.cv)||0)/100,co:(Number(form.co)||0)/100,ce:(Number(form.ce)||0)/100,rt:(Number(form.rt)||0)/100});if(e1)throw e1;await supabase.from("movimenti").insert({tipo,data:form.data,imballo:form.imballo,lotto:form.lotto,desc1:form.desc1,desc2:form.desc2,desc3:form.desc3,qta:q,magazzino:form.magazzino,contratto_id:""});flash("ok","Entrata: "+q+" kg")}
      else if(tipo==="USCITA"){const mc=fc(sel);await supabase.from("movimenti").insert({tipo:"USCITA",data:form.data,imballo:sel.imballo,lotto:sel.lotto,desc1:sel.desc1,desc2:sel.desc2,desc3:sel.desc3,qta:q,magazzino:sel.magazzino,contratto_id:sel.contratto||""});await supabase.from("lotti").update({mov:sel.mov+q}).eq("id",sel.id);if(mc)await supabase.from("contratti").update({qta_evasa:mc.qta_evasa+q}).eq("id",mc.id);flash("ok","Uscita: "+q+" kg")}
      else{const srcMag=sel.magazzino;const newImb=sel.imballo.replace(/ \(trasf\.\)/g,"");if(q<sel.d){await supabase.from("lotti").insert({sett_prod:sel.sett_prod,anno:sel.anno,imballo:newImb+" (trasf.)",lotto:sel.lotto,desc1:sel.desc1,desc2:sel.desc2,desc3:sel.desc3,q_iniz:q,mov:0,magazzino:form.newMag,mv:sel.mv,mo:sel.mo,cv:sel.cv,co:sel.co,ce:sel.ce,rt:sel.rt,contratto:sel.contratto,acquirente:sel.acquirente});await supabase.from("lotti").update({mov:sel.mov+q}).eq("id",sel.id)}else await supabase.from("lotti").update({magazzino:form.newMag}).eq("id",sel.id);await supabase.from("movimenti").insert({tipo:"TRASFERIMENTO",data:form.data,imballo:sel.imballo,lotto:sel.lotto,desc1:sel.desc1,desc2:sel.desc2,desc3:sel.desc3,qta:q,magazzino:form.newMag,contratto_id:srcMag});flash("ok","Trasferito "+q+" kg")}
      reset();await reload()}catch(e){flash("err",e.message)}finally{setLoading(false)}};
  const handleMulti=async()=>{if(loading)return;setLoading(true);const lots=av.filter(l=>selIds.includes(l.id));const dt=form.data;let ok=0;const cAcc={};for(const lot of lots){try{await supabase.from("movimenti").insert({tipo:"USCITA",data:dt,imballo:lot.imballo,lotto:lot.lotto,desc1:lot.desc1,desc2:lot.desc2,desc3:lot.desc3,qta:lot.d,magazzino:lot.magazzino,contratto_id:lot.contratto||""});await supabase.from("lotti").update({mov:lot.mov+lot.d}).eq("id",lot.id);const ct=fc(lot);if(ct){if(!cAcc[ct.id])cAcc[ct.id]=ct.qta_evasa;cAcc[ct.id]+=lot.d;await supabase.from("contratti").update({qta_evasa:cAcc[ct.id]}).eq("id",ct.id)}ok++}catch(e){}}flash("ok","Uscita "+ok+" lotti");setSelIds([]);setLoading(false);await reload()};

  const sharedFilters=<><div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap"}}><TypeChip label="Tutti" active={!fTipo} color={C.acc} onClick={()=>setFTipo("")}/>{TIPI.map(t=><TypeChip key={t} label={t} active={fTipo===t} color={TC[t]||C.acc} onClick={()=>setFTipo(fTipo===t?"":t)}/>)}<span style={{width:1,background:C.bd,margin:"0 4px"}}/><TypeChip label="Assegnati" active={fSt==="A"} color={C.b} onClick={()=>setFSt(fSt==="A"?"":"A")}/><TypeChip label="Liberi" active={fSt==="L"} color={C.g} onClick={()=>setFSt(fSt==="L"?"":"L")}/></div><div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap",alignItems:"flex-end"}}><Sel label="Calibro" value={fCal} onChange={setFCal} options={[{value:"",label:"Tutti"},...CALS.map(v=>({value:v,label:v}))]}/><Sel label="Magazzino" value={fMag} onChange={setFMag} options={[{value:"",label:"Tutti"},...MAGS.map(v=>({value:v,label:v}))]}/><Inp label={tipo==="USCITA"?"Data uscita":"Data trasferimento"} type="date" value={form.data} onChange={v=>setForm({...form,data:v})}/></div></>;
  const sharedTable=(onRowFn)=><Tbl cols={[{label:"",render:r=><input type="checkbox" checked={selIds.includes(r.id)} onClick={e=>e.stopPropagation()} onChange={()=>toggleSel(r.id)} style={{accentColor:C.acc,cursor:"pointer"}}/>},{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Disp.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:C.acc}}>{r.d.toLocaleString()} kg</span>},{key:"magazzino",label:"Mag."},{label:"M.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:moP(r)>4?C.r:moP(r)>2?C.o:C.g}}>{pct(r.mo)}</span>},{label:"C.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:coP(r)>4?C.r:coP(r)>2?C.o:C.g}}>{pct(r.co)}</span>},{label:"Contr.",render:r=>r.contratto?<Badge color={C.b} bg={C.bD}>{r.contratto}</Badge>:<span style={{color:C.tM}}>-</span>},{key:"acquirente",label:"Acq."}]} data={ufl} onRow={onRowFn}/>;

  return <div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Movimenti</h1></div><Msg msg={msg}/>
    <div style={{display:"flex",gap:0,marginBottom:20,borderRadius:10,border:"1px solid "+C.bd,overflow:"hidden",background:C.sf}} data-no-print>{[{v:"ENTRATA",color:C.g,sub:"Nuovo lotto"},{v:"USCITA",color:C.r,sub:"Seleziona e preleva"},{v:"TRASFERIMENTO",color:C.b,sub:"Sposta tra magazzini"}].map(t=><div key={t.v} onClick={()=>chTipo(t.v)} style={{flex:1,padding:"14px 20px",cursor:"pointer",textAlign:"center",background:tipo===t.v?C.zebra:"transparent",borderBottom:tipo===t.v?"3px solid "+t.color:"3px solid transparent"}}><div style={{fontSize:14,fontWeight:700,color:tipo===t.v?t.color:C.tM}}>{t.v}</div><div style={{fontSize:11,color:C.tM,marginTop:2}}>{t.sub}</div></div>)}</div>

    {tipo==="ENTRATA"&&<GCard style={{marginBottom:24}} data-no-print><h3 style={{fontSize:14,color:C.g,margin:"0 0 16px",fontWeight:700}}>Nuovo lotto in entrata</h3><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:12}}><Inp label="Data" type="date" value={form.data} onChange={v=>setForm({...form,data:v})}/><Inp label="Sett." value={form.sett} onChange={v=>setForm({...form,sett:v})}/><Inp label="Anno" value={form.anno} onChange={v=>setForm({...form,anno:v})}/><Inp label="Imballo *" value={form.imballo} onChange={v=>setForm({...form,imballo:v})} placeholder="BIG BAG N..."/><Inp label="Lotto *" value={form.lotto} onChange={v=>setForm({...form,lotto:v})} placeholder="SO112024"/><Sel label="Tipo" value={form.desc1} onChange={v=>setForm({...form,desc1:v})} options={TIPI.map(v=>({value:v,label:v}))}/><Sel label="Lavoraz." value={form.desc2} onChange={v=>setForm({...form,desc2:v})} options={LAVS.map(v=>({value:v,label:v}))}/><Sel label="Calibro" value={form.desc3} onChange={v=>setForm({...form,desc3:v})} options={CALS.map(v=>({value:v,label:v}))}/><Inp label="Qta (kg) *" type="number" value={form.qta} onChange={v=>setForm({...form,qta:v})} placeholder="1000"/><Sel label="Magazzino" value={form.magazzino} onChange={v=>setForm({...form,magazzino:v})} options={MAGS.map(v=>({value:v,label:v}))}/><Inp label="M.V. %" value={form.mv} onChange={v=>setForm({...form,mv:v})} placeholder="2"/><Inp label="M.O. %" value={form.mo} onChange={v=>setForm({...form,mo:v})} placeholder="1.3"/><Inp label="C.V. %" value={form.cv} onChange={v=>setForm({...form,cv:v})} placeholder="0"/><Inp label="C.O. %" value={form.co} onChange={v=>setForm({...form,co:v})} placeholder="3.3"/><Inp label="C.E. %" value={form.ce} onChange={v=>setForm({...form,ce:v})} placeholder="0"/><Inp label="RT %" value={form.rt} onChange={v=>setForm({...form,rt:v})} placeholder="0"/></div><div style={{marginTop:16,display:"flex",justifyContent:"flex-end",gap:10}}><Btn onClick={reset}>Annulla</Btn><Btn primary onClick={handleSubmit} disabled={loading}>{loading?"Attendere...":"Registra Entrata"}</Btn></div></GCard>}

    {tipo==="USCITA"&&<div data-no-print>{sharedFilters}
      {selIds.length>0&&<div style={{padding:"10px 16px",background:C.accL,borderRadius:8,marginBottom:14,display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:8}}><span style={{fontWeight:700,color:C.acc}}>{selIds.length} selezionati — {av.filter(l=>selIds.includes(l.id)).reduce((s,l)=>s+l.d,0).toLocaleString()} kg</span><div style={{display:"flex",gap:8}}><Btn small danger onClick={handleMulti} disabled={loading}>{loading?"Attendere...":"Registra Uscita ("+selIds.length+")"}</Btn><Btn small onClick={()=>setSelIds([])}>Deseleziona</Btn></div></div>}
      {sharedTable(r=>toggleSel(r.id))}
      <div style={{marginTop:14,padding:"12px 20px",background:C.accL,borderRadius:8,display:"flex",justifyContent:"space-between"}}><span style={{fontWeight:700,color:C.acc}}>TOTALE</span><span style={{fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{ufl.reduce((s,l)=>s+l.d,0).toLocaleString()} kg</span><span style={{color:C.tD}}>{ufl.length} lotti</span></div>
    </div>}

    {tipo==="TRASFERIMENTO"&&<div data-no-print>{sharedFilters}
      {sel&&<div style={{padding:"12px 16px",background:C.accL,borderRadius:8,marginBottom:14,display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:10}}><div style={{display:"flex",gap:16,alignItems:"center",flexWrap:"wrap"}}><div><span style={{fontSize:10,color:C.tD}}>LOTTO</span><div style={{fontWeight:800,color:C.acc}}>{sel.lotto} - {sel.imballo}</div></div><div><span style={{fontSize:10,color:C.tD}}>DISP.</span><div style={{fontWeight:800,color:C.g,fontFamily:"'DM Mono',monospace"}}>{sel.d.toLocaleString()} kg</div></div><div><span style={{fontSize:10,color:C.tD}}>DA</span><div style={{fontWeight:700}}>{sel.magazzino}</div></div></div><div style={{display:"flex",gap:8,alignItems:"flex-end"}}><Sel label="Destinazione" value={form.newMag} onChange={v=>setForm({...form,newMag:v})} options={MAGS.filter(v=>v!==sel.magazzino).map(v=>({value:v,label:v}))}/><Inp label={"Qta (max "+sel.d+")"} type="number" value={form.qta} onChange={v=>setForm({...form,qta:v})} style={{width:120}}/><Btn primary small onClick={handleSubmit} disabled={loading}>{loading?"...":"Trasferisci"}</Btn><Btn small onClick={()=>setSel(null)}>Annulla</Btn></div></div>}
      {sharedTable(r=>{setSel(r);setForm(f=>({...f,qta:String(r.d)}))})}
      <div style={{marginTop:14,padding:"12px 20px",background:C.accL,borderRadius:8,display:"flex",justifyContent:"space-between"}}><span style={{fontWeight:700,color:C.acc}}>TOTALE</span><span style={{fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{ufl.reduce((s,l)=>s+l.d,0).toLocaleString()} kg</span><span style={{color:C.tD}}>{ufl.length} lotti</span></div>
    </div>}
  </div>;
}

// === GIACENZE (with subtotal rows per tipo, MO/CO based quality) ===
function GiacenzePage({lotti,contratti,reload,isAdm,dashFilter,clearFilter}){
  const df=dashFilter||{};
  const[fTipo,setFTipo]=useState(df.type==="tipo"?df.val:df.type==="sg_cal_tipo"||df.type==="lav_tipo"||df.type==="moGrp_tipo"||df.type==="coGrp_tipo"?df.val.split("|")[1]:"");
  const[fLav,setFLav]=useState(df.type==="lav"?df.val:df.type==="sg_cal"||df.type==="sg_qual"||df.type==="sg_cal_tipo"?"SGUSCIATE":df.type==="lav_tipo"?df.val.split("|")[0]:df.type==="moGrp_tipo"||df.type==="coGrp_tipo"?"SGUSCIATE":"");
  const[fCal,setFCal]=useState(df.type==="calibro"||df.type==="sg_cal"?df.val:df.type==="sg_cal_tipo"?df.val.split("|")[0]:"");
  const[fMag,setFMag]=useState(df.type==="magazzino"?df.val:"");
  const[fSt,setFSt]=useState(df.type==="stato"?(df.val==="assegnato"?"A":"L"):"");
  const[sortQ,setSortQ]=useState("");
  const[fMoGrp,setFMoGrp]=useState(df.type==="moGrp_tipo"?df.val.split("|")[0]:"");
  const[fCoGrp,setFCoGrp]=useState(df.type==="coGrp_tipo"?df.val.split("|")[0]:"");
  const[msg,setMsg]=useState(null);
  const[selIds,setSelIds]=useState([]);const[aMode,setAMode]=useState(false);const[aC,setAC]=useState("");const[aA,setAA]=useState("");const[loading,setLoading]=useState(false);  const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),4000)};
  const enr=useMemo(()=>lotti.filter(l=>dsp(l)>0).map(l=>({...l,d:dsp(l),stato:(l.contratto||l.acquirente)?"A":"L"})),[lotti]);
  const fl=enr.filter(l=>{if(fTipo&&l.desc1!==fTipo)return false;if(fLav&&l.desc2!==fLav)return false;if(fCal&&l.desc3!==fCal)return false;if(fMag&&l.magazzino!==fMag)return false;if(fSt&&l.stato!==fSt)return false;if(fMoGrp!==""){if(grp(moP(l))!==Number(fMoGrp))return false}if(fCoGrp!==""){if(grp(coP(l))!==Number(fCoGrp))return false}return true});
  const sorted=useMemo(()=>[...fl].sort(sortQ?(a,b)=>{const va=((a[sortQ]||0)*100);const vb=((b[sortQ]||0)*100);return vb-va}:stdSort),[fl,sortQ]);

  // Build subtotal rows by grouping
  const dataWithSubs=useMemo(()=>{if(sortQ)return sorted;
    const result=[];
    // Group by tipo > lav > cal
    const tipoGroups={};sorted.forEach(l=>{const tk=l.desc1;if(!tipoGroups[tk])tipoGroups[tk]=[];tipoGroups[tk].push(l)});
    Object.entries(tipoGroups).forEach(([tipo,tipoItems])=>{
      const lavGroups={};tipoItems.forEach(l=>{const lk=l.desc2;if(!lavGroups[lk])lavGroups[lk]=[];lavGroups[lk].push(l)});
      const lavEntries=Object.entries(lavGroups).sort((a,b)=>(LAV_ORD[a[0]]??9)-(LAV_ORD[b[0]]??9));
      lavEntries.forEach(([lav,lavItems])=>{
        const calGroups={};lavItems.forEach(l=>{const ck=l.desc3;if(!calGroups[ck])calGroups[ck]=[];calGroups[ck].push(l)});
        const calEntries=Object.entries(calGroups).sort((a,b)=>(CAL_ORD[a[0]]??99)-(CAL_ORD[b[0]]??99));
        calEntries.forEach(([cal,calItems])=>{
          calItems.forEach(l=>result.push(l));
          if(calEntries.length>1||lavEntries.length>1){const sub=calcSub(calItems);result.push({_sub:true,_level:"cal",_label:cal,...sub})}
        });
        if(lavEntries.length>1||Object.keys(tipoGroups).length>1){const sub=calcSub(lavItems);result.push({_sub:true,_level:"lav",_label:lav,...sub});result.push({_blank:true})}
      });
      const sub=calcSub(tipoItems);result.push({_sub:true,_level:"tipo",_tipo:tipo,...sub});result.push({_blank:true});
    });
    return result;
  },[sorted,sortQ]);

  const totKg=sorted.reduce((s,l)=>s+l.d,0);const oc=contratti.filter(c=>(c.qta_tot-c.qta_evasa)>0);
  const fc2=lot=>contratti.find(c=>c.id===lot.contratto&&(c.qta_tot-c.qta_evasa)>0);
  const toggleSel=id=>setSelIds(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);
  const allSel=sorted.length>0&&sorted.every(l=>selIds.includes(l.id));
  const toggleAll=()=>allSel?setSelIds([]):setSelIds(sorted.map(l=>l.id));
  const doBulkUscita=async()=>{if(loading)return;setLoading(true);const lots=sorted.filter(l=>selIds.includes(l.id));const dt=new Date().toISOString().split("T")[0];let ok=0;const cAcc={};for(const lot of lots){try{await supabase.from("movimenti").insert({tipo:"USCITA",data:dt,imballo:lot.imballo,lotto:lot.lotto,desc1:lot.desc1,desc2:lot.desc2,desc3:lot.desc3,qta:lot.d,magazzino:lot.magazzino,contratto_id:lot.contratto||""});await supabase.from("lotti").update({mov:lot.mov+lot.d}).eq("id",lot.id);const ct=fc2(lot);if(ct){if(!cAcc[ct.id])cAcc[ct.id]=ct.qta_evasa;cAcc[ct.id]+=lot.d;await supabase.from("contratti").update({qta_evasa:cAcc[ct.id]}).eq("id",ct.id)}ok++}catch(e){}}flash("ok","Uscita "+ok+" lotti");setSelIds([]);setLoading(false);await reload()};
  const doBulkAssign=async()=>{if(loading)return;if(!aC&&!aA){flash("err","Seleziona contratto o acquirente");return}setLoading(true);const ct=contratti.find(c=>c.id===aC);const ids=sorted.filter(l=>selIds.includes(l.id)&&l.stato==="L").map(l=>l.id);for(const id of ids)await supabase.from("lotti").update({contratto:aC,acquirente:aC?ct?.cliente||aA:aA}).eq("id",id);setSelIds([]);setAMode(false);setAC("");setAA("");flash("ok","Assegnati "+ids.length+" lotti");setLoading(false);await reload()};
  const doUn=async id=>{await supabase.from("lotti").update({contratto:"",acquirente:""}).eq("id",id);flash("ok","Rimosso");await reload()};

  return <div>
    {dashFilter&&<div style={{marginBottom:12,display:"flex",alignItems:"center",gap:8}} data-no-print><span onClick={clearFilter} style={{fontSize:13,color:C.acc,cursor:"pointer",fontWeight:600}}>Dashboard</span><span style={{color:C.tM}}>/</span><span style={{fontSize:13,fontWeight:600}}>{df.val}</span></div>}
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}><div><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Giacenze</h1><p style={{color:C.tM,margin:"4px 0 0",fontSize:13}}>{sorted.length} lotti — {totKg.toLocaleString()} kg</p></div><XBtn data={sorted} cols={XC.giacenze} name="giacenze"/></div><Msg msg={msg}/>
    <div style={{display:"flex",gap:8,marginBottom:10,flexWrap:"wrap"}} data-no-print><TypeChip label="Tutti" active={!fTipo} color={C.acc} onClick={()=>setFTipo("")}/>{TIPI.map(t=><TypeChip key={t} label={t} active={fTipo===t} color={TC[t]||C.acc} onClick={()=>setFTipo(fTipo===t?"":t)}/>)}<span style={{width:1,background:C.bd,margin:"0 4px"}}/><TypeChip label="Assegnati" active={fSt==="A"} color={C.b} onClick={()=>setFSt(fSt==="A"?"":"A")}/><TypeChip label="Liberi" active={fSt==="L"} color={C.g} onClick={()=>setFSt(fSt==="L"?"":"L")}/></div>
    <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}} data-no-print>{LAVS.map(l=><TypeChip key={l} label={l} active={fLav===l} color={l==="SGUSCIATE"?C.g:l==="ROTTAME"?C.o:C.r} onClick={()=>setFLav(fLav===l?"":l)}/>)}</div>
    <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap",alignItems:"flex-end"}} data-no-print><Sel label="Calibro" value={fCal} onChange={setFCal} options={[{value:"",label:"Tutti"},...CALS.map(v=>({value:v,label:v}))]}/><Sel label="Magazzino" value={fMag} onChange={setFMag} options={[{value:"",label:"Tutti"},...MAGS.map(v=>({value:v,label:v}))]}/><Sel label="M.O. gruppo" value={fMoGrp} onChange={setFMoGrp} options={[{value:"",label:"Tutti"},...GRP.map((g,i)=>({value:String(i),label:g.l}))]}/><Sel label="C.O. gruppo" value={fCoGrp} onChange={setFCoGrp} options={[{value:"",label:"Tutti"},...GRP.map((g,i)=>({value:String(i),label:g.l}))]}/><Sel label="Ordina per" value={sortQ} onChange={setSortQ} options={[{value:"",label:"Standard"},{value:"mo",label:"M.O. (decrescente)"},{value:"co",label:"C.O. (decrescente)"},{value:"mv",label:"M.V."},{value:"cv",label:"C.V."},{value:"ce",label:"C.E."},{value:"rt",label:"RT"}]}/>{(fTipo||fLav||fCal||fMag||fSt||sortQ||fMoGrp||fCoGrp)&&<Btn small onClick={()=>{setFTipo("");setFLav("");setFCal("");setFMag("");setFSt("");setSortQ("");setFMoGrp("");setFCoGrp("");if(clearFilter)clearFilter()}}>Pulisci</Btn>}</div>
    {selIds.length>0&&(()=>{const selLots=sorted.filter(l=>selIds.includes(l.id));const sub=calcSub(selLots);return <div style={{position:"sticky",top:0,zIndex:3,padding:"10px 16px",background:C.accL,borderRadius:8,marginBottom:14,border:"2px solid "+C.acc,boxShadow:"0 4px 16px rgba(0,0,0,0.1)"}} data-no-print><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:8}}><span style={{fontWeight:700,color:C.acc}}>{selIds.length} selezionati — {sub.t.toLocaleString()} kg</span><div style={{display:"flex",gap:8}}><Btn small danger onClick={doBulkUscita}>Uscita selezionati</Btn><Btn small primary onClick={()=>setAMode(true)}>Assegna selezionati</Btn><Btn small onClick={()=>setSelIds([])}>Deseleziona</Btn></div></div><div style={{display:"flex",gap:12,marginTop:8,fontSize:11,flexWrap:"wrap"}}><span>M.V. <b>{sub.mv}%</b></span><span>M.O. <b style={{color:Number(sub.mo)>4?C.r:Number(sub.mo)>2?C.o:C.g}}>{sub.mo}%</b></span><span>C.V. <b>{sub.cv}%</b></span><span>C.O. <b style={{color:Number(sub.co)>4?C.r:Number(sub.co)>2?C.o:C.g}}>{sub.co}%</b></span><span>C.E. <b>{sub.ce}%</b></span><span>RT <b>{sub.rt}%</b></span></div></div>})()}
    {aMode&&<GCard style={{marginBottom:14}} data-no-print><h3 style={{fontSize:14,color:C.acc,margin:"0 0 10px",fontWeight:700}}>Assegna {selIds.length} lotti</h3><div style={{display:"flex",gap:12,alignItems:"flex-end",flexWrap:"wrap"}}><Sel label="Contratto" value={aC} onChange={v=>{setAC(v);if(v){const c=contratti.find(x=>x.id===v);if(c)setAA(c.cliente)}}} options={[{value:"",label:"- Nessuno -"},...oc.map(c=>({value:c.id,label:c.id+" - "+c.cliente+" "+(c.qta_tot-c.qta_evasa).toLocaleString()+" kg"}))]} style={{flex:"1 1 300px"}}/><Inp label="Oppure acquirente" value={aA} onChange={setAA} disabled={!!aC}/><Btn primary small onClick={doBulkAssign}>Assegna</Btn><Btn small onClick={()=>{setAMode(false);setAC("");setAA("")}}>Annulla</Btn></div></GCard>}
    <Tbl cols={[
      {label:<input type="checkbox" checked={allSel} onChange={toggleAll} style={{accentColor:C.acc,cursor:"pointer"}}/>,render:r=><input type="checkbox" checked={selIds.includes(r.id)} onClick={e=>e.stopPropagation()} onChange={()=>toggleSel(r.id)} style={{accentColor:C.acc,cursor:"pointer"}}/>,subRender:()=>""},
      {label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>,subRender:r=>r._level==="tipo"?"TOTALE "+r._tipo:r._level==="lav"?"Tot. "+r._label:"Tot. "+r._label},
      {key:"desc2",label:"Lav.",subRender:()=>""},{key:"desc3",label:"Cal.",subRender:()=>""},{key:"lotto",label:"Lotto",subRender:r=>r.n+" lotti"},{key:"imballo",label:"Imballo",subRender:()=>""},
      {label:"Disp.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:C.acc}}>{r.d.toLocaleString()} kg</span>,subRender:r=>r.t.toLocaleString()+" kg"},
      {key:"magazzino",label:"Mag.",subRender:()=>""},
      {label:"M.V.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12}}>{pct(r.mv)}</span>,subRender:r=>"m "+r.mv+"%"},
      {label:"M.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:moP(r)>4?C.r:moP(r)>2?C.o:C.g}}>{pct(r.mo)}</span>,subRender:r=>"m "+r.mo+"%"},
      {label:"C.V.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12}}>{pct(r.cv)}</span>,subRender:r=>"m "+r.cv+"%"},
      {label:"C.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:coP(r)>4?C.r:coP(r)>2?C.o:C.g}}>{pct(r.co)}</span>,subRender:r=>"m "+r.co+"%"},
      {label:"C.E.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12}}>{pct(r.ce)}</span>,subRender:r=>"m "+r.ce+"%"},
      {label:"RT",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:(r.rt||0)>0?C.o:C.tM}}>{pct(r.rt)}</span>,subRender:r=>"m "+r.rt+"%"},
      {label:"Stato",render:r=>r.stato==="A"?<span style={{display:"flex",gap:4,alignItems:"center"}}><Badge color={C.b} bg={C.bD}>{r.contratto} {r.acquirente}</Badge><button onClick={e=>{e.stopPropagation();doUn(r.id)}} style={{background:"none",border:"none",color:C.r,cursor:"pointer",fontSize:12}}>x</button></span>:<Badge color={C.g} bg={C.gD}>Libero</Badge>,subRender:()=>""}
    ]} data={dataWithSubs} onRow={r=>!r._sub&&toggleSel(r.id)}/>
    <div style={{marginTop:16,padding:"14px 20px",background:C.accL,borderRadius:10,border:"1px solid "+C.acc+"33",display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontWeight:700,color:C.acc}}>TOTALE GENERALE</span><span style={{fontSize:20,fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{totKg.toLocaleString()} kg</span><span style={{fontSize:13,color:C.tD}}>{sorted.length} lotti</span></div>
  </div>;
}

// === LOTTI ===
function LottiPage({lotti,reload,isAdm}){
  const[f,setF]=useState({d1:"",st:""});const[eId,setEId]=useState(null);const[dId,setDId]=useState(null);const[msg,setMsg]=useState(null);const[form,setForm]=useState({});
  const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),4000)};
  const openEdit=l=>{setEId(l.id);setForm({imballo:l.imballo,lotto:l.lotto,desc1:l.desc1,desc2:l.desc2,desc3:l.desc3,q_iniz:String(l.q_iniz),magazzino:l.magazzino,mv:String(((l.mv||0)*100).toFixed(2)),mo:String(((l.mo||0)*100).toFixed(2)),cv:String(((l.cv||0)*100).toFixed(2)),co:String(((l.co||0)*100).toFixed(2)),ce:String(((l.ce||0)*100).toFixed(2)),rt:String(((l.rt||0)*100).toFixed(2))})};
  const doSave=async()=>{try{await supabase.from("lotti").update({imballo:form.imballo,lotto:form.lotto,desc1:form.desc1,desc2:form.desc2,desc3:form.desc3,q_iniz:Number(form.q_iniz),magazzino:form.magazzino,mv:(Number(form.mv)||0)/100,mo:(Number(form.mo)||0)/100,cv:(Number(form.cv)||0)/100,co:(Number(form.co)||0)/100,ce:(Number(form.ce)||0)/100,rt:(Number(form.rt)||0)/100}).eq("id",eId);setEId(null);flash("ok","Aggiornato");await reload()}catch(e){flash("err",e.message)}};
  const doDel=async id=>{try{await supabase.from("lotti").delete().eq("id",id);setDId(null);flash("ok","Eliminato");await reload()}catch(e){flash("err",e.message)}};
  const fl=[...lotti.filter(l=>{if(f.d1&&l.desc1!==f.d1)return false;if(f.st==="D"&&dsp(l)<=0)return false;if(f.st==="E"&&dsp(l)>0)return false;return true})].sort(stdSort);
  return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><div><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Lotti</h1><p style={{color:C.tM,margin:"4px 0 0",fontSize:13}}>{fl.length} lotti</p></div><XBtn data={fl} cols={XC.lotti} name="lotti"/></div><Msg msg={msg}/>
  <div style={{display:"flex",gap:10,marginBottom:16}} data-no-print><Sel label="Tipo" value={f.d1} onChange={v=>setF({...f,d1:v})} options={[{value:"",label:"Tutti"},...TIPI.map(v=>({value:v,label:v}))]}/><Sel label="Stato" value={f.st} onChange={v=>setF({...f,st:v})} options={[{value:"",label:"Tutti"},{value:"D",label:"Disponibile"},{value:"E",label:"Esaurito"}]}/></div>
  {eId&&isAdm&&<GCard style={{marginBottom:20}} data-no-print><h3 style={{fontSize:16,fontWeight:800,color:C.acc,margin:"0 0 16px"}}>Modifica lotto</h3><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:12}}><Inp label="Imballo" value={form.imballo} onChange={v=>setForm({...form,imballo:v})}/><Inp label="Lotto" value={form.lotto} onChange={v=>setForm({...form,lotto:v})}/><Sel label="Tipo" value={form.desc1} onChange={v=>setForm({...form,desc1:v})} options={TIPI.map(v=>({value:v,label:v}))}/><Sel label="Lav." value={form.desc2} onChange={v=>setForm({...form,desc2:v})} options={LAVS.map(v=>({value:v,label:v}))}/><Sel label="Cal." value={form.desc3} onChange={v=>setForm({...form,desc3:v})} options={CALS.map(v=>({value:v,label:v}))}/><Inp label="Qta (kg)" type="number" value={form.q_iniz} onChange={v=>setForm({...form,q_iniz:v})}/><Sel label="Mag." value={form.magazzino} onChange={v=>setForm({...form,magazzino:v})} options={MAGS.map(v=>({value:v,label:v}))}/><Inp label="M.V. %" value={form.mv} onChange={v=>setForm({...form,mv:v})}/><Inp label="M.O. %" value={form.mo} onChange={v=>setForm({...form,mo:v})}/><Inp label="C.V. %" value={form.cv} onChange={v=>setForm({...form,cv:v})}/><Inp label="C.O. %" value={form.co} onChange={v=>setForm({...form,co:v})}/><Inp label="C.E. %" value={form.ce} onChange={v=>setForm({...form,ce:v})}/><Inp label="RT %" value={form.rt} onChange={v=>setForm({...form,rt:v})}/></div><div style={{marginTop:16,display:"flex",justifyContent:"flex-end",gap:10}}><Btn onClick={()=>setEId(null)}>Annulla</Btn><Btn primary onClick={doSave}>Salva</Btn></div></GCard>}
  <Tbl cols={[{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Q.Iniz",render:r=><span style={{fontFamily:"'DM Mono',monospace"}}>{r.q_iniz?.toLocaleString()}</span>},{label:"Mov.",render:r=><span style={{fontFamily:"'DM Mono',monospace",color:r.mov>0?C.r:C.tM}}>{r.mov?.toLocaleString()}</span>},{label:"Disp.",render:r=>{const d=dsp(r);return <span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:d>0?C.g:C.r}}>{d.toLocaleString()}</span>}},{label:"Stato",render:r=>dsp(r)>0?<Badge color={C.g} bg={C.gD}>Disp.</Badge>:<Badge color={C.tM} bg={C.bd+"44"}>Esaurito</Badge>},{key:"magazzino",label:"Mag."},{key:"contratto",label:"Contr."},...(isAdm?[{label:"",render:r=><div style={{display:"flex",gap:6}}><button onClick={e=>{e.stopPropagation();openEdit(r)}} style={{background:"none",border:"none",color:C.acc,cursor:"pointer",fontSize:12,fontWeight:600}}>Mod</button>{dId===r.id?<span style={{display:"flex",gap:4}}><button onClick={e=>{e.stopPropagation();doDel(r.id)}} style={{background:C.r,border:"none",color:"#fff",cursor:"pointer",fontSize:11,padding:"3px 8px",borderRadius:6,fontWeight:700}}>Si</button><button onClick={e=>{e.stopPropagation();setDId(null)}} style={{background:C.sf,border:"1px solid "+C.bd,color:C.tD,cursor:"pointer",fontSize:11,padding:"3px 8px",borderRadius:6}}>No</button></span>:<button onClick={e=>{e.stopPropagation();setDId(r.id)}} style={{background:"none",border:"none",color:C.r,cursor:"pointer",fontSize:12,opacity:.7}}>Elim</button>}</div>}]:[])] } data={fl}/></div>;
}

// === CONTRATTI ===
function ContrattiPage({contratti,lotti,movimenti,reload,isAdm,dashFilter}){const[showF,setShowF]=useState(false);const[eId,setEId]=useState(null);const[dId,setDId]=useState(null);const[msg,setMsg]=useState(null);const[fCl,setFCl]=useState("");const[fTp,setFTp]=useState("");const[fSt,setFSt]=useState("");const[selContr,setSelContr]=useState(dashFilter?.type==="contr"?dashFilter.val:null);const ef={id:"",desc1:"CONVENZIONALI",desc2:"SGUSCIATE",desc3:"9/11",cliente:"",scadenza:"",qta_tot:"",qta_evasa:"0"};const[form,setForm]=useState(ef);const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),4000)};const openNew=()=>{setForm(ef);setEId(null);setShowF(true)};const openEdit=c=>{setForm({id:c.id,desc1:c.desc1,desc2:c.desc2,desc3:c.desc3,cliente:c.cliente,scadenza:c.scadenza||"",qta_tot:String(c.qta_tot),qta_evasa:String(c.qta_evasa)});setEId(c.id);setShowF(true)};const doSave=async()=>{if(!form.id||!form.cliente||!form.qta_tot){flash("err","Compila campi obbligatori");return}try{if(eId)await supabase.from("contratti").update({desc1:form.desc1,desc2:form.desc2,desc3:form.desc3,cliente:form.cliente,scadenza:form.scadenza||null,qta_tot:Number(form.qta_tot),qta_evasa:Number(form.qta_evasa)}).eq("id",eId);else{const{error}=await supabase.from("contratti").insert({id:form.id,desc1:form.desc1,desc2:form.desc2,desc3:form.desc3,cliente:form.cliente,scadenza:form.scadenza||null,qta_tot:Number(form.qta_tot),qta_evasa:Number(form.qta_evasa||0)});if(error){flash("err",error.message);return}}flash("ok",eId?"Aggiornato":"Creato");setShowF(false);setEId(null);await reload()}catch(e){flash("err",e.message)}};const doDel=async id=>{await supabase.from("lotti").update({contratto:"",acquirente:""}).eq("contratto",id);await supabase.from("contratti").delete().eq("id",id);setDId(null);flash("ok","Eliminato");await reload()};const filtered=contratti.filter(c=>{if(fCl&&!c.cliente.toUpperCase().includes(fCl.toUpperCase()))return false;if(fTp&&c.desc1!==fTp)return false;if(fSt==="A"&&(c.qta_tot-c.qta_evasa)<=0)return false;if(fSt==="C"&&(c.qta_tot-c.qta_evasa)>0)return false;return true});const contrExits=selContr?movimenti.filter(m=>m.contratto_id===selContr):[];return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Contratti</h1><div style={{display:"flex",gap:10}}><XBtn data={filtered} cols={XC.contratti} name="contratti"/>{isAdm&&<Btn primary onClick={openNew}>+ Nuovo</Btn>}</div></div><Msg msg={msg}/><div style={{display:"flex",gap:10,marginBottom:16,flexWrap:"wrap"}} data-no-print><Inp label="Cerca cliente" value={fCl} onChange={setFCl} placeholder="ITALNUX..." style={{flex:"1 1 200px"}}/><Sel label="Tipo" value={fTp} onChange={setFTp} options={[{value:"",label:"Tutti"},...TIPI.map(v=>({value:v,label:v}))]}/><Sel label="Stato" value={fSt} onChange={setFSt} options={[{value:"",label:"Tutti"},{value:"A",label:"Aperti"},{value:"C",label:"Chiusi"}]}/></div>{showF&&isAdm&&<GCard style={{marginBottom:20}} data-no-print><h3 style={{fontSize:16,fontWeight:800,color:C.acc,margin:"0 0 16px"}}>{eId?"Modifica":"Nuovo"} Contratto</h3><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:12}}><Inp label="N. *" value={form.id} onChange={v=>setForm({...form,id:v})} disabled={!!eId}/><Inp label="Cliente *" value={form.cliente} onChange={v=>setForm({...form,cliente:v})}/><Sel label="Tipo" value={form.desc1} onChange={v=>setForm({...form,desc1:v})} options={TIPI.map(v=>({value:v,label:v}))}/><Sel label="Lav." value={form.desc2} onChange={v=>setForm({...form,desc2:v})} options={LAVS.map(v=>({value:v,label:v}))}/><Sel label="Cal." value={form.desc3} onChange={v=>setForm({...form,desc3:v})} options={CALS.map(v=>({value:v,label:v}))}/><Inp label="Scadenza" type="date" value={form.scadenza} onChange={v=>setForm({...form,scadenza:v})}/><Inp label="Qta Tot *" type="number" value={form.qta_tot} onChange={v=>setForm({...form,qta_tot:v})}/>{eId&&<Inp label="Qta Evasa" type="number" value={form.qta_evasa} onChange={v=>setForm({...form,qta_evasa:v})}/>}</div><div style={{marginTop:16,display:"flex",justifyContent:"flex-end",gap:10}}><Btn onClick={()=>{setShowF(false);setEId(null)}}>Annulla</Btn><Btn primary onClick={doSave}>{eId?"Salva":"Crea"}</Btn></div></GCard>}<p style={{fontSize:12,color:C.tM,marginBottom:8}} data-no-print>Clicca un contratto per le uscite</p><Tbl cols={[{key:"id",label:"N."},{key:"cliente",label:"Cliente"},{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc3",label:"Cal."},{label:"Totale",render:r=><span style={{fontFamily:"'DM Mono',monospace"}}>{r.qta_tot?.toLocaleString()}</span>},{label:"Evasa",render:r=><span style={{fontFamily:"'DM Mono',monospace"}}>{r.qta_evasa?.toLocaleString()}</span>},{label:"Residuo",render:r=>{const res=r.qta_tot-r.qta_evasa;return<span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:res>0?C.o:C.g}}>{res.toLocaleString()}</span>}},{label:"%",render:r=>{const p=Math.min(100,r.qta_evasa/r.qta_tot*100);return<div style={{display:"flex",alignItems:"center",gap:8,minWidth:90}}><div style={{flex:1,height:4,background:C.bd+"44",borderRadius:3,overflow:"hidden"}}><div style={{height:"100%",width:p+"%",background:p>=100?C.g:C.acc,borderRadius:3}}/></div><span style={{fontSize:11,fontWeight:700,fontFamily:"'DM Mono',monospace"}}>{p.toFixed(0)}%</span></div>}},{label:"Stato",render:r=>(r.qta_tot-r.qta_evasa)>0?<Badge color={C.o} bg={C.oD}>Aperto</Badge>:<Badge color={C.g} bg={C.gD}>Chiuso</Badge>},{label:"Scad.",render:r=>fmtD(r.scadenza)},...(isAdm?[{label:"",render:r=><div style={{display:"flex",gap:6}}><button onClick={e=>{e.stopPropagation();openEdit(r)}} style={{background:"none",border:"none",color:C.acc,cursor:"pointer",fontSize:12,fontWeight:600}}>Mod</button>{dId===r.id?<span style={{display:"flex",gap:4}}><button onClick={e=>{e.stopPropagation();doDel(r.id)}} style={{background:C.r,border:"none",color:"#fff",cursor:"pointer",fontSize:11,padding:"3px 8px",borderRadius:6,fontWeight:700}}>Si</button><button onClick={e=>{e.stopPropagation();setDId(null)}} style={{background:C.sf,border:"1px solid "+C.bd,color:C.tD,cursor:"pointer",fontSize:11,padding:"3px 8px",borderRadius:6}}>No</button></span>:<button onClick={e=>{e.stopPropagation();setDId(r.id)}} style={{background:"none",border:"none",color:C.r,cursor:"pointer",fontSize:12,opacity:.7}}>Elim</button>}</div>}]:[])] } data={filtered} onRow={r=>setSelContr(selContr===r.id?null:r.id)}/>{selContr&&<div style={{marginTop:16,animation:"fadeUp .3s both"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><h3 style={{fontSize:14,color:C.acc,fontWeight:700}}>Uscite contratto N.{selContr} ({contrExits.length})</h3><Btn small onClick={()=>setSelContr(null)}>Chiudi</Btn></div>{contrExits.length>0?<Tbl cols={[{label:"Data",render:r=>fmtD(r.data)},{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Qta",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700}}>{r.qta?.toLocaleString()} kg</span>},{key:"magazzino",label:"Mag."}]} data={contrExits}/>:<p style={{color:C.tM}}>Nessuna uscita</p>}</div>}</div>;}

