function ClientiPage({lotti,movimenti}){const[selCl,setSelCl]=useState(null);const clienti=useMemo(()=>{const map={};lotti.forEach(l=>{if(l.acquirente&&!l.contratto){map[l.acquirente]=(map[l.acquirente]||0)+1}});return Object.entries(map).sort((a,b)=>a[0].localeCompare(b[0])).map(([nome,n])=>({nome,lotti:n}))},[lotti]);const exits=selCl?movimenti.filter(m=>{const lot=lotti.find(l=>l.lotto===m.lotto&&l.imballo===m.imballo);return m.tipo==="USCITA"&&lot&&lot.acquirente===selCl&&!m.contratto_id}):[];return <div><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:"0 0 8px",fontFamily:"'Playfair Display',serif"}}>Clienti</h1><p style={{color:C.tM,fontSize:13,marginBottom:20}}>Acquirenti senza contratto. Clicca per le uscite.</p><Tbl cols={[{key:"nome",label:"Cliente"},{label:"Lotti",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700}}>{r.lotti}</span>}]} data={clienti} onRow={r=>setSelCl(selCl===r.nome?null:r.nome)}/>{selCl&&<div style={{marginTop:16,animation:"fadeUp .3s both"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><h3 style={{fontSize:14,color:C.acc,fontWeight:700}}>Uscite di {selCl} ({exits.length})</h3><Btn small onClick={()=>setSelCl(null)}>Chiudi</Btn></div>{exits.length>0?<Tbl cols={[{label:"Data",render:r=>fmtD(r.data)},{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Qta",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700}}>{r.qta?.toLocaleString()} kg</span>},{key:"magazzino",label:"Mag."}]} data={exits}/>:<p style={{color:C.tM}}>Nessuna uscita</p>}</div>}</div>;}

