function RicercaPage({lotti}){const[q,setQ]=useState("");const av=lotti.filter(l=>dsp(l)>0);const res=q.length<2?[]:av.filter(l=>[l.lotto,l.imballo,l.desc1,l.desc2,l.desc3,l.magazzino,l.acquirente,l.contratto].some(v=>v&&String(v).toUpperCase().includes(q.toUpperCase()))).sort(stdSort);return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Ricerca</h1>{res.length>0&&<XBtn data={res} cols={XC.giacenze} name="ricerca"/>}</div><input value={q} onChange={e=>setQ(e.target.value)} placeholder="Cerca lotto, tipo, calibro, magazzino, acquirente..." style={{width:"100%",padding:"14px 20px",background:C.sf,border:"2px solid "+(q.length>=2?C.acc+"66":C.bd),borderRadius:10,color:C.t,fontSize:16,outline:"none",marginBottom:16,boxSizing:"border-box"}} data-no-print/>{q.length>=2&&<><p style={{color:C.tM,fontSize:13,marginBottom:12}}>{res.length} risultati</p><Tbl cols={[{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Disp.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:C.acc}}>{dsp(r).toLocaleString()} kg</span>},{key:"magazzino",label:"Mag."},{label:"M.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:moP(r)>4?C.r:moP(r)>2?C.o:C.g}}>{pct(r.mo)}</span>},{label:"C.O.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontSize:12,color:coP(r)>4?C.r:coP(r)>2?C.o:C.g}}>{pct(r.co)}</span>},{key:"contratto",label:"Contr."},{key:"acquirente",label:"Acq."}]} data={res}/></>}</div>;}

// === STORICO ===
function StoricoPage(){const[dt,setDt]=useState(new Date().toISOString().split("T")[0]);const[ld,setLd]=useState(false);const[snap,setSnap]=useState(null);const xCols=[{key:"desc1",label:"Tipo"},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{key:"ent",label:"Entrate"},{key:"usc",label:"Uscite"},{key:"disp",label:"Disp."},{key:"magazzino",label:"Mag."}];const calc=useCallback(async()=>{setLd(true);const{data:movs}=await supabase.from("movimenti").select("*").order("data").order("id");const filtered=(movs||[]).filter(m=>{const md=String(m.data||"").split("T")[0];return md<=dt});const mp={};filtered.forEach(m=>{const k=m.lotto+"||"+m.imballo;if(m.tipo==="ENTRATA"){if(!mp[k])mp[k]={lotto:m.lotto,imballo:m.imballo,desc1:m.desc1,desc2:m.desc2,desc3:m.desc3,magazzino:m.magazzino,ent:0,usc:0};mp[k].ent+=m.qta;mp[k].magazzino=m.magazzino}else if(m.tipo==="USCITA"&&mp[k])mp[k].usc+=m.qta;else if(m.tipo==="TRASFERIMENTO"&&mp[k])mp[k].magazzino=m.magazzino});const ls=Object.values(mp).map(l=>({...l,disp:l.ent-l.usc})).filter(l=>l.ent>0).sort(stdSort);const tot=ls.reduce((s,l)=>s+Math.max(0,l.disp),0);const av=ls.filter(l=>l.disp>0);setSnap({dt,ls,av,tot,nm:filtered.length});setLd(false)},[dt]);return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}><div><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Storico</h1><p style={{color:C.tM,margin:"4px 0 0",fontSize:13}}>Giacenze a una data</p></div>{snap&&<XBtn data={snap.av} cols={xCols} name={"storico_"+snap.dt}/>}</div><GCard style={{marginBottom:24,display:"flex",gap:16,alignItems:"flex-end"}} data-no-print><div style={{display:"flex",flexDirection:"column",gap:4}}><label style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:1,fontWeight:600}}>Data</label><input type="date" value={dt} onChange={e=>setDt(e.target.value)} style={{padding:"10px 14px",background:C.sf,border:"2px solid "+C.acc+"66",borderRadius:8,color:C.t,fontSize:16,outline:"none",fontFamily:"'DM Mono',monospace"}}/></div><Btn primary onClick={calc} disabled={ld}>{ld?"Calcolo...":"Visualizza al "+fmtD(dt)}</Btn></GCard>{snap&&<><div style={{display:"flex",gap:14,flexWrap:"wrap",marginBottom:20}}><GCard><div style={{fontSize:10,color:C.tD,textTransform:"uppercase",letterSpacing:1.5,fontWeight:600}}>Giacenza al {fmtD(snap.dt)}</div><div style={{fontSize:26,fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace",marginTop:6}}>{snap.tot.toLocaleString()} kg</div><div style={{fontSize:12,color:C.tM,marginTop:4}}>{snap.av.length} lotti</div></GCard></div><Tbl cols={[{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Entrate",render:r=><span style={{fontFamily:"'DM Mono',monospace",color:C.g}}>{r.ent.toLocaleString()}</span>},{label:"Uscite",render:r=><span style={{fontFamily:"'DM Mono',monospace",color:r.usc>0?C.r:C.tM}}>{r.usc.toLocaleString()}</span>},{label:"Disp.",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700,color:r.disp>0?C.acc:C.r}}>{r.disp.toLocaleString()} kg</span>},{key:"magazzino",label:"Mag."}]} data={snap.ls}/><div style={{marginTop:14,padding:"12px 20px",background:C.accL,borderRadius:8,display:"flex",justifyContent:"space-between"}}><span style={{fontWeight:700,color:C.acc}}>TOTALE</span><span style={{fontWeight:900,color:C.acc,fontFamily:"'DM Mono',monospace"}}>{snap.tot.toLocaleString()} kg</span></div></>}{!snap&&!ld&&<div style={{textAlign:"center",padding:60,color:C.tM}}><p>Seleziona una data e clicca Visualizza</p></div>}</div>;}

// === STORICO MOVIMENTI ===
function StoricoMovPage({movimenti,lotti,contratti,reload}){const[undoId,setUndoId]=useState(null);const[msg,setMsg]=useState(null);const[selMov,setSelMov]=useState(null);const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),4000)};const handleUndo=async r=>{try{if(r.tipo==="ENTRATA"){const{data:lots}=await supabase.from("lotti").select("id").match({imballo:r.imballo,lotto:r.lotto,q_iniz:r.qta}).limit(1);if(lots&&lots[0])await supabase.from("lotti").delete().eq("id",lots[0].id)}else if(r.tipo==="USCITA"){const{data:lots}=await supabase.from("lotti").select("*").match({imballo:r.imballo,lotto:r.lotto,desc1:r.desc1,desc2:r.desc2,desc3:r.desc3}).limit(1);if(lots&&lots[0])await supabase.from("lotti").update({mov:Math.max(0,lots[0].mov-r.qta)}).eq("id",lots[0].id);if(r.contratto_id&&!r.contratto_id.includes(" ")){const{data:ct}=await supabase.from("contratti").select("*").eq("id",r.contratto_id).single();if(ct)await supabase.from("contratti").update({qta_evasa:Math.max(0,ct.qta_evasa-r.qta)}).eq("id",ct.id)}}else{const srcMag=r.contratto_id;if(srcMag){await supabase.from("lotti").update({magazzino:srcMag}).match({imballo:r.imballo,lotto:r.lotto,desc1:r.desc1,magazzino:r.magazzino}).limit(1)}}await supabase.from("movimenti").delete().eq("id",r.id);setUndoId(null);setSelMov(null);flash("ok","Annullato");await reload()}catch(e){flash("err",e.message)}};const enriched=useMemo(()=>movimenti.map(m=>{const lot=lotti.find(l=>l.lotto===m.lotto&&l.imballo===m.imballo);return{...m,lot,cliente:lot?.contratto?contratti.find(c=>c.id===lot.contratto)?.cliente||"":"",acquirente:lot?.acquirente||""}}),[movimenti,lotti,contratti]);const selLot=selMov?enriched.find(m=>m.id===selMov)?.lot:null;return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}><div><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Storico Movimenti</h1><p style={{color:C.tM,margin:"4px 0 0",fontSize:13}}>{enriched.length} movimenti — clicca per dettaglio</p></div><XBtn data={enriched} cols={XC.movimenti} name="storico_movimenti"/></div><Msg msg={msg}/>{selLot&&<div style={{padding:"12px 16px",background:C.accL,borderRadius:8,marginBottom:14,display:"flex",gap:16,flexWrap:"wrap",alignItems:"center",animation:"fadeUp .2s both"}} data-no-print><span style={{fontWeight:700,color:C.acc}}>{selLot.lotto} - {selLot.imballo}</span><span>M.V. <b>{pct(selLot.mv)}</b></span><span>M.O. <b style={{color:moP(selLot)>4?C.r:moP(selLot)>2?C.o:C.g}}>{pct(selLot.mo)}</b></span><span>C.V. <b>{pct(selLot.cv)}</b></span><span>C.O. <b style={{color:coP(selLot)>4?C.r:coP(selLot)>2?C.o:C.g}}>{pct(selLot.co)}</b></span><span>C.E. <b>{pct(selLot.ce)}</b></span><span>RT <b>{pct(selLot.rt)}</b></span><Btn small onClick={()=>setSelMov(null)}>Chiudi</Btn></div>}<Tbl cols={[{label:"Mov.",render:r=><Badge color={r.tipo==="ENTRATA"?C.g:r.tipo==="USCITA"?C.r:C.b} bg={r.tipo==="ENTRATA"?C.gD:r.tipo==="USCITA"?C.rD:C.bD}>{r.tipo}</Badge>},{label:"Data",render:r=>fmtD(r.data)},{label:"Tipo",render:r=><Badge color={TC[r.desc1]||C.acc} bg={(TC[r.desc1]||C.acc)+"18"}>{r.desc1}</Badge>},{key:"desc2",label:"Lav."},{key:"desc3",label:"Cal."},{key:"lotto",label:"Lotto"},{key:"imballo",label:"Imballo"},{label:"Qta",render:r=><span style={{fontFamily:"'DM Mono',monospace",fontWeight:700}}>{r.qta?.toLocaleString()}</span>},{key:"magazzino",label:"Mag."},{label:"Contr.",render:r=>r.contratto_id?<Badge color={C.b} bg={C.bD}>{r.contratto_id}</Badge>:<span style={{color:C.tM}}>-</span>},{key:"cliente",label:"Cliente"},{key:"acquirente",label:"Acq."},{label:"",render:r=>undoId===r.id?<div style={{display:"flex",gap:4,alignItems:"center"}}><span style={{fontSize:11,color:C.o}}>Sicuro?</span><button onClick={e=>{e.stopPropagation();handleUndo(r)}} style={{background:C.r,border:"none",color:"#fff",cursor:"pointer",fontSize:11,padding:"4px 10px",borderRadius:6,fontWeight:700}}>Si</button><button onClick={e=>{e.stopPropagation();setUndoId(null)}} style={{background:C.sf,border:"1px solid "+C.bd,color:C.tD,cursor:"pointer",fontSize:11,padding:"4px 8px",borderRadius:6}}>No</button></div>:<button onClick={e=>{e.stopPropagation();setUndoId(r.id)}} style={{background:"none",border:"none",color:C.r,cursor:"pointer",fontSize:12,opacity:.7}}>Annulla</button>}]} data={enriched} onRow={r=>setSelMov(selMov===r.id?null:r.id)}/></div>;}

// === UTENTI ===
function UtentiPage(){const[users,setUsers]=useState([]);const[msg,setMsg]=useState(null);const[showN,setShowN]=useState(false);const[nE,setNE]=useState("");const[nP,setNP]=useState("");const[nN,setNN]=useState("");const[nR,setNR]=useState("operatore");const flash=(t,x)=>{setMsg({t,x});setTimeout(()=>setMsg(null),4000)};const load=useCallback(async()=>{const{data}=await supabase.from("user_profiles").select("*").order("created_at");setUsers(data||[])},[]);useEffect(()=>{load()},[load]);const create=async()=>{if(!nE||!nP){flash("err","Email e password obbligatori");return}const{data,error}=await supabase.auth.signUp({email:nE,password:nP});if(error){flash("err",error.message);return}if(data.user)await supabase.from("user_profiles").update({nome:nN,ruolo:nR}).eq("id",data.user.id);setShowN(false);setNE("");setNP("");setNN("");flash("ok","Utente creato");await load()};const toggle=async u=>{const nr=u.ruolo==="admin"?"operatore":"admin";await supabase.from("user_profiles").update({ruolo:nr}).eq("id",u.id);flash("ok","Aggiornato");await load()};return <div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h1 style={{fontSize:28,fontWeight:900,color:C.t,margin:0,fontFamily:"'Playfair Display',serif"}}>Utenti</h1><Btn primary onClick={()=>setShowN(true)}>+ Nuovo</Btn></div><Msg msg={msg}/>{showN&&<GCard style={{marginBottom:20}}><h3 style={{fontSize:16,fontWeight:800,color:C.acc,margin:"0 0 16px"}}>Nuovo Utente</h3><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:12}}><Inp label="Email *" value={nE} onChange={setNE} placeholder="mario@assofrutti.it"/><Inp label="Password *" value={nP} onChange={setNP} type="password"/><Inp label="Nome" value={nN} onChange={setNN}/><Sel label="Ruolo" value={nR} onChange={setNR} options={[{value:"operatore",label:"Operatore"},{value:"admin",label:"Admin"}]}/></div><div style={{marginTop:16,display:"flex",justifyContent:"flex-end",gap:10}}><Btn onClick={()=>setShowN(false)}>Annulla</Btn><Btn primary onClick={create}>Crea</Btn></div></GCard>}<Tbl cols={[{key:"email",label:"Email"},{key:"nome",label:"Nome"},{label:"Ruolo",render:r=><Badge color={r.ruolo==="admin"?C.acc:C.b} bg={r.ruolo==="admin"?C.accL:C.bD}>{r.ruolo}</Badge>},{label:"",render:r=><Btn small onClick={()=>toggle(r)}>{r.ruolo==="admin"?"Rendi Operatore":"Rendi Admin"}</Btn>}]} data={users}/></div>;}

// === MAIN APP ===
const NAV=[{id:"dashboard",icon:"\u25c6",label:"Dashboard"},{id:"movimenti",icon:"\u2195",label:"Movimenti"},{id:"giacenze",icon:"\u25a3",label:"Giacenze"},{id:"contratti",icon:"\u25c8",label:"Contratti"},{id:"clienti",icon:"\u263a",label:"Clienti"},{id:"ricerca",icon:"\u2315",label:"Ricerca"},{id:"storico",icon:"\u23f0",label:"Storico"},{id:"storicomov",icon:"\u2630",label:"Storico Mov."}];
export default function App(){
  const[session,setSession]=useState(null);const[profile,setProfile]=useState(null);const[authLd,setAuthLd]=useState(true);
  const[page,setPage]=useState("dashboard");const[lotti,setLotti]=useState([]);const[contratti,setContratti]=useState([]);const[movimenti,setMovimenti]=useState([]);const[sO,setSO]=useState(true);const[dbErr,setDbErr]=useState(null);const[dashFilter,setDashFilter]=useState(null);
  const[theme,setTheme]=useState("light");C=theme==="dark"?DARK:LIGHT;
  const toggleTheme=t=>{setTheme(t);try{window.localStorage.setItem("af_theme",t)}catch(e){}};
  useEffect(()=>{try{const s=window.localStorage.getItem("af_theme");if(s)setTheme(s)}catch(e){}},[]);
  useEffect(()=>{supabase.auth.getSession().then(({data:{session:s}})=>{setSession(s);if(!s)setAuthLd(false)});const{data:{subscription}}=supabase.auth.onAuthStateChange((_,s)=>{setSession(s);if(!s){setProfile(null);setAuthLd(false)}});return()=>subscription.unsubscribe()},[]);
  useEffect(()=>{if(!session?.user)return;supabase.from("user_profiles").select("*").eq("id",session.user.id).single().then(({data})=>{setProfile(data);setAuthLd(false)})},[session]);
  const loadAll=useCallback(async()=>{try{const[lr,cr,mr]=await Promise.all([supabase.from("lotti").select("*").order("id"),supabase.from("contratti").select("*").order("id"),supabase.from("movimenti").select("*").order("id",{ascending:false}).limit(5000)]);if(lr.error)throw lr.error;setLotti(lr.data||[]);setContratti(cr.data||[]);setMovimenti(mr.data||[]);setDbErr(null)}catch(e){setDbErr(e.message)}},[]);
  useEffect(()=>{if(session)loadAll()},[session,loadAll]);
  if(authLd)return <div style={{height:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.bg,color:C.acc,fontSize:18,fontFamily:"'DM Sans',sans-serif"}}><style>{CSS}</style>Caricamento...</div>;
  if(!session)return <LoginPage/>;
  if(dbErr)return <div style={{height:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:C.bg,flexDirection:"column",gap:16,fontFamily:"'DM Sans',sans-serif"}}><style>{CSS}</style><div style={{color:C.r,fontSize:18,fontWeight:700}}>Errore connessione</div><div style={{color:C.tM,fontSize:13,maxWidth:400,textAlign:"center"}}>{dbErr}</div><Btn primary onClick={loadAll}>Riprova</Btn></div>;
  const isAdm=profile?.ruolo==="admin";const navItems=[...NAV,...(isAdm?[{id:"lotti",icon:"\u25a4",label:"Lotti"},{id:"utenti",icon:"\u2699",label:"Utenti"}]:[])];
  const logout=async()=>{await supabase.auth.signOut()};const goPage=(p,filter)=>{setPage(p);setDashFilter(filter||null)};
  const pg=()=>{switch(page){case"dashboard":return <DashboardPage lotti={lotti} contratti={contratti} goPage={goPage}/>;case"movimenti":return <MovimentiPage lotti={lotti} contratti={contratti} reload={loadAll}/>;case"giacenze":return <GiacenzePage lotti={lotti} contratti={contratti} reload={loadAll} isAdm={isAdm} dashFilter={dashFilter} clearFilter={()=>{setDashFilter(null);setPage("dashboard")}}/>;case"lotti":return isAdm?<LottiPage lotti={lotti} reload={loadAll} isAdm={isAdm}/>:null;case"contratti":return <ContrattiPage contratti={contratti} lotti={lotti} movimenti={movimenti} reload={loadAll} isAdm={isAdm} dashFilter={dashFilter}/>;case"clienti":return <ClientiPage lotti={lotti} movimenti={movimenti}/>;case"ricerca":return <RicercaPage lotti={lotti}/>;case"storico":return <StoricoPage/>;case"storicomov":return <StoricoMovPage movimenti={movimenti} lotti={lotti} contratti={contratti} reload={loadAll}/>;case"utenti":return isAdm?<UtentiPage/>:null;default:return null}};
  return <div style={{display:"flex",height:"100vh",background:C.bg,fontFamily:"'DM Sans','Segoe UI',sans-serif",color:C.t,overflow:"hidden"}}><style>{CSS}</style>
    <div data-no-print style={{width:sO?220:60,background:C.sf,borderRight:"1px solid "+C.bd,display:"flex",flexDirection:"column",transition:"width .25s",flexShrink:0,overflow:"hidden"}}><div style={{padding:sO?"18px 16px":"18px 14px",borderBottom:"1px solid "+C.bd,display:"flex",alignItems:"center",gap:12,cursor:"pointer",minHeight:62}} onClick={()=>setSO(!sO)}><div style={{width:34,height:34,borderRadius:10,background:"linear-gradient(135deg,"+C.acc+","+C.accD+")",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:900,color:"#fff",flexShrink:0}}>A</div>{sO&&<div><div style={{fontSize:14,fontWeight:800,color:C.acc,letterSpacing:1,lineHeight:1.1}}>ASSOFRUTTI</div><div style={{fontSize:9,color:C.tM,letterSpacing:2,marginTop:2}}>MAGAZZINO</div></div>}</div>
    <nav style={{flex:1,padding:"10px 8px",overflowY:"auto"}}>{navItems.map(item=><div key={item.id} onClick={()=>goPage(item.id)} style={{display:"flex",alignItems:"center",gap:12,padding:sO?"9px 12px":"9px 14px",borderRadius:8,marginBottom:2,cursor:"pointer",background:page===item.id?C.accL:"transparent",borderLeft:page===item.id?"3px solid "+C.acc:"3px solid transparent",transition:"all .15s"}} onMouseEnter={e=>{if(page!==item.id)e.currentTarget.style.background=C.sfH}} onMouseLeave={e=>{if(page!==item.id)e.currentTarget.style.background="transparent"}}><span style={{fontSize:15,opacity:page===item.id?1:.4,flexShrink:0}}>{item.icon}</span>{sO&&<span style={{fontSize:13,fontWeight:page===item.id?700:400,color:page===item.id?C.acc:C.tD,whiteSpace:"nowrap"}}>{item.label}</span>}</div>)}</nav>
    {sO&&<div style={{padding:"14px 16px",borderTop:"1px solid "+C.bd}}><div style={{display:"flex",gap:4,marginBottom:12}}><button onClick={()=>toggleTheme("light")} style={{flex:1,padding:"6px",borderRadius:6,border:"1px solid "+(theme==="light"?C.acc:C.bd),background:theme==="light"?C.accL:"transparent",cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center",gap:4}}><span>&#9788;</span><span style={{fontSize:10,color:theme==="light"?C.acc:C.tM,fontWeight:600}}>Chiaro</span></button><button onClick={()=>toggleTheme("dark")} style={{flex:1,padding:"6px",borderRadius:6,border:"1px solid "+(theme==="dark"?C.acc:C.bd),background:theme==="dark"?C.accL:"transparent",cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center",gap:4}}><span>&#9790;</span><span style={{fontSize:10,color:theme==="dark"?C.acc:C.tM,fontWeight:600}}>Scuro</span></button></div><div style={{fontSize:12,color:C.tD,marginBottom:6,fontWeight:500}}>{profile?.nome||session?.user?.email}</div><Badge color={isAdm?C.acc:C.b} bg={isAdm?C.accL:C.bD}>{profile?.ruolo||"..."}</Badge><div style={{display:"flex",gap:8,marginTop:12}}><Btn small onClick={loadAll} style={{flex:1,fontSize:11}}>Aggiorna</Btn><Btn small onClick={logout} style={{flex:1,fontSize:11}}>Esci</Btn></div></div>}
    </div><div style={{flex:1,overflow:"auto",padding:"24px 28px",background:C.bg}}>{pg()}</div></div>;
}
